 1→import { useState } from 'react'
 2→import { setAuthToken } from '../store'
 3→import { api } from '../api'
 4→
 5→interface Props { onAuth: () => void }
 6→
 7→export default function Auth({ onAuth }: Props) {
 8→  const [token, setToken] = useState('')
 9→  const [error, setError] = useState('')
10→  const [loading, setLoading] = useState(false)
11→
12→  const handleSubmit = async () => {
13→    if (!token.trim()) { setError('Please enter your access token'); return }
14→    setLoading(true)
15→    setError('')
16→    setAuthToken(token.trim())
17→    try {
18→      const h = await api.health()
19→      if (h.status === 'ok') { onAuth() }
20→      else { setError('Unexpected response — check server'); setAuthToken('') }
21→    } catch (err) {
22→      const msg = err instanceof Error ? err.message : 'Unknown error'
23→      if (msg.includes('Unauthorized') || msg.includes('401')) {
24→        setError('Wrong token — check your APP_SECRET value')
25→      } else {
26→        setError('Cannot reach server — is it running?')
27→      }
28→      setAuthToken('')
29→    } finally { setLoading(false) }
30→  }
31→
32→  return (
33→    <div className="auth-gate">
34→      <div className="auth-card">
35→        <div className="auth-emoji">🎯</div>
36→        <h1 className="auth-title">DECODE</h1>
37→        <p className="auth-tagline">Direction · Execute · Close · Observe · Develop · Evolve</p>
38→        <div className="auth-divider" />
39→        <p className="auth-label">Enter your access token to continue</p>
40→        <input
41→          className={`auth-input ${error ? 'invalid' : ''}`}
42→          type="password"
43→          placeholder="Access token..."
44→          value={token}
45→          onChange={e => { setToken(e.target.value); setError('') }}
46→          onKeyDown={e => e.key === 'Enter' && handleSubmit()}
47→          autoFocus
48→        />
49→        {error && <div className="auth-error">{error}</div>}
50→        <button className="btn-primary btn-full mt-2" onClick={handleSubmit} disabled={loading}>
51→          {loading ? <span className="spinner show" /> : null}
52→          {loading ? 'Checking...' : 'Enter'}
53→        </button>
54→        <p className="auth-hint">Token is set via APP_SECRET in your .env file or Cloud Run environment variables.</p>
55→      </div>
56→    </div>
57→  )
58→}

 1→import { Component, type ReactNode } from 'react'
 2→
 3→interface Props {
 4→  children: ReactNode
 5→  fallback?: ReactNode
 6→}
 7→
 8→interface State {
 9→  hasError: boolean
10→  error: Error | null
11→}
12→
13→export default class ErrorBoundary extends Component<Props, State> {
14→  state: State = { hasError: false, error: null }
15→
16→  static getDerivedStateFromError(error: Error): State {
17→    return { hasError: true, error }
18→  }
19→
20→  componentDidCatch(error: Error, info: React.ErrorInfo) {
21→    console.error('[ErrorBoundary]', error, info.componentStack)
22→  }
23→
24→  render() {
25→    if (this.state.hasError) {
26→      if (this.props.fallback) return this.props.fallback
27→
28→      return (
29→        <div style={{
30→          padding: 32,
31→          textAlign: 'center',
32→          color: 'var(--text)',
33→          maxWidth: 400,
34→          margin: '60px auto',
35→        }}>
36→          <div style={{ fontSize: 40, marginBottom: 16 }}>⚠️</div>
37→          <h2 style={{
38→            fontFamily: 'var(--font-display)',
39→            fontSize: 18,
40→            fontWeight: 700,
41→            marginBottom: 8,
42→            color: 'var(--accent)',
43→          }}>
44→            Something went wrong
45→          </h2>
46→          <p style={{
47→            fontSize: 13,
48→            color: 'var(--muted2)',
49→            lineHeight: 1.6,
50→            marginBottom: 20,
51→          }}>
52→            {this.state.error?.message || 'An unexpected error occurred.'}
53→          </p>
54→          <button
55→            onClick={() => window.location.reload()}
56→            style={{
57→              background: 'var(--surface2)',
58→              border: '1px solid var(--border2)',
59→              borderRadius: 'var(--radius-sm)',
60→              color: 'var(--text)',
61→              padding: '10px 24px',
62→              fontSize: 13,
63→              cursor: 'pointer',
64→            }}
65→          >
66→            Reload app
67→          </button>
68→        </div>
69→      )
70→    }
71→
72→    return this.props.children
73→  }
74→}
