 48→  50%     { transform: translateY(-4px); }
 49→}
 50→@keyframes float {
 51→  0%,100% { transform: translateY(0); }
 52→  50%     { transform: translateY(-5px); }
 53→}
 54→@keyframes shake {
 55→  0%,100% { transform: translateX(0); }
 56→  20%     { transform: translateX(-4px); }
 57→  60%     { transform: translateX(4px); }
 58→  80%     { transform: translateX(-2px); }
